function [nmbTrc,trcLst] = fTrcLstV02(sDir,scop)%% return number of tracfiles(timingtrace) saved and list of it% Kei Nakamura% Created on Friday, December 18th 2009.% Modified on Tuesday, May 4th 2010.% nmbTrc: number of traces exist in scnDir% trcLst: trace file list (shot number)% sDir: search directory to look at% scop:   1 for pixi, 2 for tek6, 3 for 3GHz scopeif scop==1; % pixi    name = '/*timingtrace*.txt';    trcLst = dir([sDir,name]);         % information for Scan* fileelseif scop==2; % tek6    name = '/*_Tek6_*.txt';    trcLst = dir([sDir,name]);         % information for Scan* fileelseif scop==3; % 3GHz    name = '/*_BPM1_*.txt';    trcLst = dir([sDir,name]);         % information for Scan* fileendnmbTrc = numel(trcLst);   % number of traces
